function Avatar({ expert, size = 56, showRing = false }) {
  const [imgError, setImgError] = useState(false);
  return (
    <div style={{
      width: size, height: size, borderRadius: "50%", overflow: "hidden", flexShrink: 0,
      border: showRing ? "1px solid #333" : "1px solid #222",
      background: "#111",
    }}>
      {!imgError ? (
        <img
          src={expert.photoUrl}
          alt={expert.name}
          onError={() => setImgError(true)}
          style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "top center", filter: "grayscale(100%) contrast(1.1) brightness(0.9)" }}
        />
      ) : (
        <div style={{
          width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center",
          background: "#1c1c1c", fontSize: size * 0.32, fontWeight: 700, color: "#555", letterSpacing: "-0.02em",
        }}>
          {expert.initials}
        </div>
      )}
    </div>
  );
}

export default function Home() {
  const [view, setView] = useState("home");
  const [activeExpert, setActiveExpert] = useState(null);
  const [superTeam, setSuperTeam] = useState(false);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);
  const taRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);
  useEffect(() => {
    if (taRef.current) {
      taRef.current.style.height = "auto";
      taRef.current.style.height = Math.min(taRef.current.scrollHeight, 140) + "px";
    }
  }, [input]);

  const go = (expert) => { setActiveExpert(expert); setSuperTeam(false); setMessages([]); setView("chat"); };
  const goSuper = () => { setActiveExpert(null); setSuperTeam(true); setMessages([]); setView("chat"); };

  const send = async (override) => {
    const text = (override || input).trim();
    if (!text || loading) return;
    const msg = { role: "user", content: text };
    const hist = [...messages, msg];
    setMessages(hist); setInput(""); setLoading(true);
    try {
      const res = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-5",
          max_tokens: 1000,
          system: superTeam ? SUPER_TEAM_PROMPT : activeExpert.systemPrompt,
          messages: hist,
        }),
      });
      const data = await res.json();
      if (data.error) {
        setMessages([...hist, { role: "assistant", content: `API Error: ${data.error?.message || data.error?.type || JSON.stringify(data.error)}` }]);
      } else {
        const reply = data.content?.map(b => b.text || "").join("") || "Empty response. Try again.";
        setMessages([...hist, { role: "assistant", content: reply }]);
      }
    } catch (err) {
      setMessages([...hist, { role: "assistant", content: `Connection error: ${err.message}` }]);
    }
    setLoading(false);
  };

  const onKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } };

  const renderMsg = (text) => {
    return text.split("\n").map((line, i) => {
      if (line === "---") return <div key={i} style={{ borderTop: "1px solid #2a2a2a", margin: "18px 0" }} />;
      const parts = line.split(/(\*\*[^*]+\*\*)/g).map((p, j) =>
        p.startsWith("**") && p.endsWith("**")
          ? <strong key={j} style={{ color: "#fff", fontWeight: 600 }}>{p.slice(2, -2)}</strong>
          : p
      );
      return <span key={i}>{parts}<br /></span>;
    });
  };

  return (
    <>
      <Head>
        <title>AI Super Team</title>
        <meta name="description" content="5 Marketing Legends. 1 Advisory Board." />
        <meta name="viewport" content="width=device-width, initial-scale=1" />
      </Head>

      <div style={{ minHeight: "100vh", background: "#080808", color: "#999", fontFamily: "\'Helvetica Neue\', Helvetica, Arial, sans-serif", display: "flex", flexDirection: "column" }}>

        {/* NAV */}
        <nav style={{ background: "#080808", borderBottom: "1px solid #111", padding: "0 20px", height: 52, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 30 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            {view === "chat" && (
              <button onClick={() => setView("home")} style={{ background: "none", border: "none", color: "#777", cursor: "pointer", fontSize: 11, letterSpacing: "0.12em", textTransform: "uppercase", padding: 0, display: "flex", alignItems: "center", gap: 6 }}>
                <span style={{ fontSize: 14 }}>←</span> Board
              </button>
            )}
            {view === "home" && (
              <span style={{ fontSize: 11, color: "#555", letterSpacing: "0.18em", textTransform: "uppercase", fontWeight: 500 }}>AI Super Team</span>
            )}
          </div>
          {view === "chat" && (
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              {superTeam
                ? <div style={{ width: 32, height: 32, borderRadius: "50%", background: "#111", border: "1px solid #222", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>⚡</div>
                : <Avatar expert={activeExpert} size={32} />
              }
              <div>
                <div style={{ fontSize: 13, fontWeight: 600, color: "#ddd" }}>{superTeam ? "AI Super Team" : activeExpert?.name}</div>
                <div style={{ fontSize: 10, color: "#555", letterSpacing: "0.08em", textTransform: "uppercase" }}>{superTeam ? "Full Advisory Board" : activeExpert?.title}</div>
              </div>
            </div>
          )}
          <div style={{ width: 60 }} />
        </nav>

        {/* HOME */}
        {view === "home" && (
          <div style={{ flex: 1, maxWidth: 680, margin: "0 auto", width: "100%", padding: "52px 20px 72px" }}>
            <div style={{ marginBottom: 52 }}>
              <div style={{ fontSize: 10, letterSpacing: "0.35em", color: "#555", textTransform: "uppercase", marginBottom: 16 }}>Marketing Advisory Board</div>
              <h1 style={{ fontSize: "clamp(36px, 8vw, 58px)", fontWeight: 300, lineHeight: 1.08, margin: "0 0 16px", letterSpacing: "-0.04em", color: "#e8e8e8" }}>
                Five legends.<br /><span style={{ color: "#888" }}>One question.</span>
              </h1>
              <p style={{ color: "#666", fontSize: 13, maxWidth: 340, lineHeight: 1.8, margin: 0 }}>
                Choose an expert for deep-dive advice, or run the full board for a synthesized 30-day action plan.
              </p>
            </div>

            <button onClick={goSuper} style={{ width: "100%", marginBottom: 20, padding: "20px 22px", background: "#111", border: "1px solid #222", borderRadius: 8, cursor: "pointer", display: "flex", alignItems: "center", gap: 16, textAlign: "left", transition: "all 0.2s" }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = "#444"; e.currentTarget.style.background = "#161616"; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = "#222"; e.currentTarget.style.background = "#111"; }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gridTemplateRows: "1fr 1fr", gap: 2, width: 44, height: 44, flexShrink: 0 }}>
                {EXPERTS.slice(0, 4).map(e => (
                  <div key={e.id} style={{ borderRadius: 3, overflow: "hidden" }}><Avatar expert={e} size={20} /></div>
                ))}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 14, color: "#ddd", fontWeight: 600, marginBottom: 3 }}>Run the Full Board ⚡</div>
                <div style={{ fontSize: 11, color: "#666" }}>All 5 experts · Synthesis + 30-day action plan</div>
              </div>
              <span style={{ color: "#666", fontSize: 18 }}>→</span>
            </button>

            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 16 }}>
              <div style={{ flex: 1, height: 1, background: "#111" }} />
              <span style={{ fontSize: 10, color: "#444", letterSpacing: "0.2em", textTransform: "uppercase" }}>or consult one expert</span>
              <div style={{ flex: 1, height: 1, background: "#111" }} />
            </div>

            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {EXPERTS.map(e => (
                <button key={e.id} onClick={() => go(e)} style={{ background: "#111", border: "1px solid #1e1e1e", borderRadius: 8, padding: "14px 18px", cursor: "pointer", display: "flex", alignItems: "center", gap: 14, textAlign: "left", width: "100%", transition: "all 0.18s" }}
                  onMouseEnter={el => { el.currentTarget.style.borderColor = "#3a3a3a"; el.currentTarget.style.background = "#161616"; }}
                  onMouseLeave={el => { el.currentTarget.style.borderColor = "#1e1e1e"; el.currentTarget.style.background = "#111"; }}>
                  <Avatar expert={e} size={44} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: "flex", alignItems: "baseline", gap: 8, marginBottom: 2 }}>
                      <span style={{ fontSize: 13, fontWeight: 600, color: "#ddd" }}>{e.name}</span>
                      <span style={{ fontSize: 10, color: "#555", letterSpacing: "0.08em", textTransform: "uppercase" }}>{e.title}</span>
                    </div>
                    <div style={{ fontSize: 11, color: "#666" }}>{e.bio}</div>
                  </div>
                  <span style={{ color: "#555", fontSize: 16, flexShrink: 0 }}>→</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* CHAT */}
        {view === "chat" && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", maxWidth: 720, margin: "0 auto", width: "100%" }}>
            <div style={{ flex: 1, overflowY: "auto", padding: "28px 20px 8px" }}>

              {messages.length === 0 && (
                <div>
                  <div style={{ display: "flex", alignItems: "flex-start", gap: 18, marginBottom: 32, paddingBottom: 28, borderBottom: "1px solid #111" }}>
                    {superTeam
                      ? <div style={{ width: 72, height: 72, borderRadius: "50%", background: "#111", border: "1px solid #1e1e1e", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, flexShrink: 0 }}>⚡</div>
                      : <Avatar expert={activeExpert} size={72} showRing />
                    }
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 10, color: "#555", letterSpacing: "0.2em", textTransform: "uppercase", marginBottom: 6 }}>
                        {superTeam ? "Full Advisory Board" : activeExpert?.era}
                      </div>
                      <div style={{ fontSize: 22, fontWeight: 300, color: "#e0e0e0", letterSpacing: "-0.02em", marginBottom: 4 }}>
                        {superTeam ? "AI Super Team" : activeExpert?.name}
                      </div>
                      <div style={{ fontSize: 12, color: "#777", marginBottom: 10 }}>
                        {superTeam ? "Five experts. Five frameworks. One synthesized action plan." : activeExpert?.bio}
                      </div>
                      {!superTeam && (
                        <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                          {activeExpert?.frameworks.map(f => (
                            <span key={f} style={{ fontSize: 10, padding: "2px 8px", border: "1px solid #333", borderRadius: 3, color: "#666", letterSpacing: "0.04em" }}>{f}</span>
                          ))}
                        </div>
                      )}
                      {superTeam && (
                        <div style={{ display: "flex", gap: 6 }}>
                          {EXPERTS.map(e => <Avatar key={e.id} expert={e} size={24} />)}
                        </div>
                      )}
                    </div>
                  </div>

                  <div>
                    <div style={{ fontSize: 10, color: "#555", letterSpacing: "0.2em", textTransform: "uppercase", marginBottom: 10 }}>Suggested questions</div>
                    {(superTeam
                      ? ["Run the super team: I run a [business] doing $[X]/month and want to hit $[Y]", "Ask all 5 experts: Should I raise my prices from $[X] to $[Y]?", "I\'m stuck at $[X]/month. What would each expert prioritize?", "I\'m launching [product]. Full board strategic review."]
                      : activeExpert?.starters || []
                    ).map((s, i) => (
                      <button key={i} onClick={() => setInput(s)} style={{ display: "block", width: "100%", background: "none", border: "1px solid #222", borderRadius: 6, padding: "10px 13px", cursor: "pointer", color: "#666", fontSize: 12, textAlign: "left", marginBottom: 5, transition: "all 0.15s" }}
                        onMouseEnter={e => { e.currentTarget.style.color = "#bbb"; e.currentTarget.style.borderColor = "#444"; }}
                        onMouseLeave={e => { e.currentTarget.style.color = "#666"; e.currentTarget.style.borderColor = "#222"; }}>
                        {s}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {messages.map((msg, i) => (
                <div key={i} style={{ marginBottom: 20 }}>
                  {msg.role === "user" ? (
                    <div style={{ display: "flex", justifyContent: "flex-end" }}>
                      <div style={{ background: "#161616", border: "1px solid #2a2a2a", borderRadius: "10px 10px 2px 10px", padding: "11px 15px", maxWidth: "75%", fontSize: 13, lineHeight: 1.65, color: "#ccc" }}>
                        {msg.content}
                      </div>
                    </div>
                  ) : (
                    <div>
                      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
                        {superTeam
                          ? <div style={{ width: 28, height: 28, borderRadius: "50%", background: "#111", border: "1px solid #1e1e1e", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12 }}>⚡</div>
                          : <Avatar expert={activeExpert} size={28} />
                        }
                        <span style={{ fontSize: 11, color: "#555", letterSpacing: "0.08em", textTransform: "uppercase" }}>
                          {superTeam ? "AI Super Team" : activeExpert?.name}
                        </span>
                      </div>
                      <div style={{ background: "#111", border: "1px solid #222", borderRadius: "2px 10px 10px 10px", padding: "16px 18px", fontSize: 13, lineHeight: 1.9, color: "#c0c0c0" }}>
                        {renderMsg(msg.content)}
                      </div>
                    </div>
                  )}
                </div>
              ))}

              {loading && (
                <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 0" }}>
                  {superTeam
                    ? <div style={{ width: 28, height: 28, borderRadius: "50%", background: "#111", border: "1px solid #1e1e1e", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12 }}>⚡</div>
                    : <Avatar expert={activeExpert} size={28} />
                  }
                  <div style={{ display: "flex", gap: 4 }}>
                    {[0, 1, 2].map(i => (
                      <div key={i} style={{ width: 4, height: 4, borderRadius: "50%", background: "#666", animation: "pulse 1.3s ease-in-out infinite", animationDelay: `${i * 0.2}s` }} />
                    ))}
                  </div>
                </div>
              )}
              <div ref={bottomRef} />
            </div>

            <div style={{ padding: "10px 20px 24px", borderTop: "1px solid #1a1a1a" }}>
              <div style={{ background: "#111", border: "1px solid #2a2a2a", borderRadius: 10, padding: "6px 6px 6px 14px", display: "flex", alignItems: "flex-end", gap: 8 }}
                onFocusCapture={e => e.currentTarget.style.borderColor = "#444"}
                onBlurCapture={e => e.currentTarget.style.borderColor = "#2a2a2a"}>
                <textarea ref={taRef} value={input} onChange={e => setInput(e.target.value)} onKeyDown={onKey} rows={1}
                  placeholder={superTeam ? "Describe your situation — all 5 experts will respond…" : `Ask ${activeExpert?.name}…`}
                  style={{ flex: 1, background: "none", border: "none", color: "#ddd", fontSize: 13, resize: "none", outline: "none", lineHeight: 1.65, padding: "7px 0", overflowY: "auto", fontFamily: "inherit" }} />
                <button onClick={() => send()} disabled={!input.trim() || loading}
                  style={{ background: input.trim() && !loading ? "#e0e0e0" : "#1e1e1e", border: "none", borderRadius: 7, padding: "9px 14px", cursor: input.trim() && !loading ? "pointer" : "not-allowed", color: input.trim() && !loading ? "#080808" : "#444", fontSize: 14, fontWeight: 700, flexShrink: 0, transition: "all 0.18s" }}>
                  ↑
                </button>
              </div>
              <div style={{ fontSize: 10, color: "#333", textAlign: "center", marginTop: 7, letterSpacing: "0.08em" }}>Return to send · Shift+Return for new line</div>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
